# Gerado a partir de spark/sql/ (pasta sql removida; conteúdo embutido para paridade com dbt).

PIPELINE_SQL = "-- Grain: 1 linha = 1 convênio (deduplicado por cd_convenio)\n-- Fonte: silver_context.procedimento via glue_catalog.silver_context.procedimento\n-- Camada: Gold | Tipo: SCD1\n-- Dimensão conformada — compartilhada entre fatos assistenciais e financeiros\n-- ⚠️  SCD1 provisório: migrar para SCD2 quando silver_context.convenio estiver disponível\n\n\nWITH source AS (\n    SELECT * FROM glue_catalog.silver_context.procedimento\n    WHERE cd_convenio <> -1\n)\n\n, convenio_ranked AS (\n    SELECT\n        cd_convenio\n      , cd_grupo\n      , ROW_NUMBER() OVER (\n            PARTITION BY cd_convenio\n            ORDER BY _context_processed_at DESC\n        ) AS rn\n    FROM source\n)\n\n, final AS (\n    SELECT\n          md5(concat_ws('||', coalesce(cast(cd_convenio as string), '_dbt_utils_surrogate_key_null_')))  AS sk_convenio\n        , cd_convenio                                             AS nk_convenio\n        , cd_grupo\n        , FROM_UTC_TIMESTAMP(CURRENT_TIMESTAMP(), 'America/Sao_Paulo') AS _gold_loaded_at\n    FROM convenio_ranked\n    WHERE rn = 1\n)\n\nSELECT * FROM final\n"
